args.sqlite_command:
UPDATE J09A_temp
SET ENTSCHEIDUNG = (
  SELECT base_entscheidung FROM J09A_haus_class h
  WHERE h.HAUS = J09A_temp.HAUS
);

args.sql_query:
SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1, CITY2, EMAIL
FROM J09A_final
WHERE ENTSCHEIDUNG = 'MANDATORY_READING';

SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1, CITY2, EMAIL
FROM J09A_final
WHERE ENTSCHEIDUNG <> 'MANDATORY_READING' OR ENTSCHEIDUNG IS NULL;
